function sortedSquares(nums: number[]): number[] {
  const out = new Array(nums.length);
  let i = 0, j = nums.length - 1, k = nums.length - 1;
  while (i <= j) {
    const a = nums[i] * nums[i], b = nums[j] * nums[j];
    if (a > b) { out[k--] = a; i++; } else { out[k--] = b; j--; }
  }
  return out;
}
